fn main() {
    let decimal: f64 = 97.99;
    let integer: i32 = decimal as i32;  // truncates to 97
    let character: char = integer as u8 as char;  // 'a'

    println!("decimal: {}, integer: {}, char: {}", decimal, integer, character);

    let parsed: i32 = "42".parse().expect("Not a number");
    println!("parsed: {}", parsed);
